mapper.select:
SELECT id, title, body, state, current_version, created_by, published_at, created_at, updated_at
FROM published_content
WHERE id = #{id}

mapper.update:
UPDATE published_content
SET title = #{title},
    body = #{body},
    current_version = #{currentVersion},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE published_content
SET state = #{state},
    published_at = #{publishedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}
